#ifndef AND_COMBINATOR_H
#define AND_COMBINATOR_H
#include <Arduino.h>

class ANDCombinator {
public:
    ANDCombinator(int inputCount = 2);
    void setInput(int index, bool value);
    bool compute();
    bool getResult() const;
private:
    bool* _inputs;
    int _count;
    bool _result;
};

#endif

firmware_template.source:
#include "and_combinator.h"

ANDCombinator::ANDCombinator(int inputCount)
    : _count(inputCount), _result(false) {
    _inputs = new bool[inputCount];
    for (int i = 0; i < inputCount; i++) _inputs[i] = false;
}

void ANDCombinator::setInput(int index, bool value) {
    if (index >= 0 && index < _count) _inputs[index] = value;
}

bool ANDCombinator::compute() {
    _result = true;
    for (int i = 0; i < _count; i++) {
        if (!_inputs[i]) { _result = false; break; }
    }
    return _result;
}

bool ANDCombinator::getResult() const { return _result; }
